insert into public.vendas_itens_import_raw (
  empresa_id, lote_ref, source_row_num, source_item_id, pedido_legacy_id_raw, tipo_venda_raw, produto_legacy_id_raw, produto_nome_raw, quantidade_raw, valor_unitario_raw, total_raw, margem_raw, custo_unitario_raw, custo_total_raw, qtd_disponivel_raw, payload
)
select
  e.id,
  'itens_vendas_2026_07_10',
  src.source_row_num,
  src.source_item_id,
  src.pedido_legacy_id_raw,
  src.tipo_venda_raw,
  src.produto_legacy_id_raw,
  src.produto_nome_raw,
  src.quantidade_raw,
  src.valor_unitario_raw,
  src.total_raw,
  src.margem_raw,
  src.custo_unitario_raw,
  src.custo_total_raw,
  src.qtd_disponivel_raw,
  jsonb_build_object(
    'source_item_id', src.source_item_id,
    'pedido_legacy_id', src.pedido_legacy_id_raw,
    'tipo_venda', src.tipo_venda_raw,
    'produto_legacy_id', src.produto_legacy_id_raw,
    'produto_nome', src.produto_nome_raw,
    'quantidade', src.quantidade_raw,
    'valor_unitario', src.valor_unitario_raw,
    'total', src.total_raw,
    'margem', src.margem_raw,
    'custo_unitario', src.custo_unitario_raw,
    'custo_total', src.custo_total_raw,
    'qtd_disponivel', src.qtd_disponivel_raw
  )
from e cross join src
on conflict (empresa_id, source_item_id)
do update set
  lote_ref = excluded.lote_ref,
  source_row_num = excluded.source_row_num,
  pedido_legacy_id_raw = excluded.pedido_legacy_id_raw,
  tipo_venda_raw = excluded.tipo_venda_raw,
  produto_legacy_id_raw = excluded.produto_legacy_id_raw,
  produto_nome_raw = excluded.produto_nome_raw,
  quantidade_raw = excluded.quantidade_raw,
  valor_unitario_raw = excluded.valor_unitario_raw,
  total_raw = excluded.total_raw,
  margem_raw = excluded.margem_raw,
  custo_unitario_raw = excluded.custo_unitario_raw,
  custo_total_raw = excluded.custo_total_raw,
  qtd_disponivel_raw = excluded.qtd_disponivel_raw,
  payload = excluded.payload;
